const items = $input.all();

// Извлекаем все элементы
let articles = [];
for (const item of items) {
    if (item.json && Array.isArray(item.json)) {
        articles.push(...item.json);
    } else if (item.json) {
        articles.push(item.json);
    } else if (item.title) {
        articles.push(item);
    }
}

if (articles.length === 0 && items[0]?.json && Array.isArray(items[0].json)) {
    articles = items[0].json;
}

if (!Array.isArray(articles) || articles.length === 0) {
    throw new Error('Не удалось извлечь массив новостей');
}

// Преобразуем в единый формат
const newsWithFields = articles.map(item => ({
    title: item.title || '',
    link: item.link || item.url || '',
    description: item.contentSnippet || item.content || item.description || ''
}));

// Фильтрация (без белого и чёрного списков)
const filtered = newsWithFields;

// Удаление дубликатов по заголовку
const uniqueNews = [];
const seenTitles = new Set();

for (const item of filtered) {
    const normalizedTitle = item.title.toLowerCase().replace(/[^\w\s]/g, '');
    if (!seenTitles.has(normalizedTitle)) {
        seenTitles.add(normalizedTitle);
        uniqueNews.push(item);
    }
}

// Берём первые 10 новостей
const topNews = uniqueNews.slice(0, 10);

// Формируем текст письма (простой текст, без HTML)
let body = `📰 Дайджест новостей ИИ\n\n`;
if (topNews.length === 0) {
    body += 'Новостей по теме ИИ за сегодня не найдено.\n';
} else {
    topNews.forEach((item, index) => {
        body += `${index + 1}. **${item.title}**\n`;
        body += `   🔗 ${item.link}\n`;
        if (item.description) {
            const desc = item.description.substring(0, 200);
            body += `   📝 ${desc}${desc.length >= 200 ? '...' : ''}\n`;
        }
        body += `\n`;
    });
}

body += `\n---\nПисьмо сгенерировано автоматически в n8n`;
return { newsList: body };
